@module samplePage  src=samplePage.lua  loc=71  sha=fa87f15  mode=chunk
@deps cm, cmgr, chrome, gui, facade

# Imports
  @require fs = 'fs'  @ 11
      @contract  builds the substack (sm/sv local, only sv leaves); lifecycle drives sm/sv directly
      @contract  owns its active track: the renderer's picker sets sv; probe take comes from the arrange facade in tick
      @contract  render hooks delegate to sampleRender
  @require util = 'util'  @ 12

# Constructed sub-instances
  @construct sm = util.instantiate('sampleManager')  @ 25
  @construct sv = util.instantiate('sampleView')  @ 26
  @construct sr = util.instantiate('sampleRender')  @ 27

# Private state
  @state sp = {}  @ 30

# Private functions
  @fn arrange()  @ 21

# Public API (sp:*)
  -- Page lifecycle (track ops on sv, JSFX poll on sm)
  @api sp:bind()  @ 37
      @contract  bind seeds a default track on first activation; the page owns its track thereafter
  @api sp:setTrack(track)  @ 45
      @contract  setTrack re-keys cm to the given track via sv; the sample facade and the picker drive it
  @api sp:listTracks()  @ 50
      @contract  listTracks proxies sm:listTracks via sv — coord queries this to seed its active sampler track on first activation
  @api sp:unbind()  @ 53
      @contract  unbind reverts any preview-in-place but leaves cm and sv state alone — the next bind can resume on the same track
  @api sp:tick()  @ 56
      @contract  tick runs every frame; watchPath + sm:tick always; probeMode skipped if no current take
  -- Page interface — render delegates to the renderer
  @api sp:renderToolbarBits(ctx)  @ 66
  @api sp:renderBody(ctx, w, h, dispatch)  @ 67
  @api sp:renderStatusBar(ctx)  @ 68
  @api sp:focusState()  @ 69

# Uses (outbound edges)
  @use call    facade.get  @ 21
  @use call    facade.publish  @ 63
  @use call    sampleManager.probeMode  @ 58
  @use call    sampleManager.tick  @ 60
  @use call    sampleManager.watchPath  @ 59
  @use call    sampleRender.closeTransients  @ 53
  @use call    sampleRender.focusState  @ 69
  @use call    sampleRender.renderBody  @ 67
  @use call    sampleRender.renderStatusBar  @ 68
  @use call    sampleRender.renderToolbarBits  @ 66
  @use call    sampleView.getTrack  @ 38
  @use call    sampleView.listTracks  @ 39, 50
  @use call    sampleView.setTrack  @ 40, 46
  @use call    util.instantiate  @ 25, 26, 27
  @use require fs  @ 11
  @use require sampleManager  @ 25
  @use require sampleRender  @ 27
  @use require sampleView  @ 26
  @use require util  @ 12

